    const result: AnthropicModelsResponse = formatAnthropicResponse([
      { id: "claude-3-opus", createdAt: "2024-02-29T00:00:00Z" },
    ]);
    expect(result.data[0].created_at).toBe("2024-02-29T00:00:00Z");
  });

