    const result: AnthropicModelsResponse = formatAnthropicResponse([
      { id: "claude-3-opus", createdAt: "2026-05-29T17:22:44.350+08:00" },
    ]);
    expect(result.data[0].created_at).toBe("2026-05-29T09:22:44Z");
  });

