export type CodexReasoningEffortPreference =
  | "inherit"
  | "none"
  | "minimal"
  | "low"
  | "medium"
  | "high"
  | "xhigh";

export type CodexReasoningSummaryPreference = "inherit" | "auto" | "detailed";

export type CodexTextVerbosityPreference = "inherit" | "low" | "medium" | "high";

